#include <stdio.h>
#include <stdlib.h>
#define MAX_N 3000
#define MAX_M 3000
// Define the graph structure
typedef struct {
    int num_stations;
    int num_edges;
    int **edges;
    int *traffic;
} Graph;
// Function to read the graph from input
Graph *read_graph() {
    Graph *graph = (Graph *)malloc(sizeof(Graph));
    scanf("%d", &graph->num_stations);
    graph->traffic = (int *)malloc(graph->num_stations * sizeof(int));
    for (int i = 0; i < graph->num_stations; i++) {
        scanf("%d", &graph->traffic[i]);
    }
    graph->num_edges = graph->num_stations - 1;
    graph->edges = (int **)malloc(graph->num_edges * sizeof(int *));
    for (int i = 0; i < graph->num_edges; i++) {
        graph->edges[i] = (int *)malloc(2 * sizeof(int));
        scanf("%d %d", &graph->edges[i][0], &graph->edges[i][1]);
    }
    return graph;
}
// Function to compute the minimum cut
int min_cut(Graph *graph) {
    // Implement the minimum cut algorithm here
    // For simplicity, we will use a brute force approach
    int min_cut = INT_MAX;
    for (int i = 0; i < graph->num_stations; i++) {
        for (int j = i + 1; j < graph->num_stations; j++) {
            int cut = 0;
            for (int k = 0; k < graph->num_edges; k++) {
                if ((graph->edges[k][0] <= i && graph->edges[k][1] > i) || (graph->edges[k][0] <= j && graph->edges[k][1] > j)) {
                    cut += graph->traffic[graph->edges[k][0]] + graph->traffic[graph->edges[k][1]];
                }
            }
            min_cut = min(min_cut, cut);
        }
    }
    return min_cut;
}
int main() {
    Graph *graph = read_graph();
    int min_cut_value = min_cut(graph);
    printf("%d\n", min_cut_value);
    return 0;
}

